;◆イベント◆

; 初期発生イベント
events = [3]

;-------------------------------------------------------------------------------
*event_1
;[exp] true

; 戦闘チュートリアル
@addevent name=戦闘 num=1
@monster pos=2 name=スライム
@monster pos=3 name=スライム
@monster pos=4 name=スライム
@callbattle gameover=true
@delevent

[texton w=5]
[マックス f=03]「Alright! It's a big victory!」[k]
[マックス f=01]「Oh? It looks like the enemy dropped a treasure chest. What kind of treasure is in it? Let's open it right away.」[k]
[マックス f=01]「Oops, be careful, [b]treasure chests are usually trapped[/b]. First, carefully [b]disarm the trap[/b].」[k]
[マックス f=01]「It's a good idea to check the party's opinions to determine the type.」[k]
[textoff]

@addevent name=全般 num=44
@treasure item=革の手袋,木の盾,金貨（小） trap=石つぶて level=1

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@delevent
@wait time=500
[texton w=5]
[マックス f=03]「Oh, there's a treasure chest over there! Lucky! Let's get it right away.」[k]
[b]In dungeons, various things like [b red]treasure chests,[r]signposts, and buttons[/b] can be found.[/b][k]
[b]Move to them, [b]then [b red]click[b] them with the mouse, or[r][b red]Option button[b] (By default, the space key or the third[r]button on the gamepad).[/b][k]
[textoff]

[eventoff]
